Your task is to write a Jest test case that exposes a specific mutation in a JavaScript/TypeScript project.

MUTATION DETAILS
The mutation affects the following file:
sinks/drain.js
Here is the full content of that file (shown with a <PLACEHOLDER> marker):
'use strict'

module.exports = function drain (op, done) {
  var read, abort

  // Declared here so that it captures the drain's stack trace
  var doneLackingErr
  if (!done) {
    doneLackingErr = new Error('no done callback supplied')
  }

  function sink (_read) {
    read = _read
    if(abort) return sink.abort()
    //this function is much simpler to write if you
    //just use recursion, but by using a while loop
    //we do not blow the stack if the stream happens to be sync.
    ;(function next() {
        var loop = true, cbed = false
        while(loop) {
          cbed = false
          read(null, function (end, data) {
            cbed = true
            if(end = end || abort) {
              loop = false
              if(done) done(end === true ? null : end)
              <PLACEHOLDER>
                console.warn(doneLackingErr)
                throw end
              }
            }
            else if(op && false === op(data) || abort) {
              loop = false
              read(abort || true, done || function () {})
            }
            else if(!loop){
              next()
            }
          })
          if(!cbed) {
            loop = false
            return
          }
        }
      })()
  }

  sink.abort = function (err, cb) {
    if('function' == typeof err)
      cb = err, err = true
    abort = err || true
    if(read) return read(abort, cb || function () {})
  }

  return sink
}

In the original code, <PLACEHOLDER> has the value:

-                 else if(end && end !== true) {
In the mutated code, <PLACEHOLDER> has the value:

+                 else if(true) {


YOUR TASK
Write one Jest test file that:
    1. Passes when run against the original code.
    2. Fails when run against the mutated code.
    3. Tests the behavior of the mutated file in a way that reliably detects the mutation.
The test will be saved at the following path, relative to this test-generation project’s root:
llm-cache/anthropic_claude-sonnet-4.6/temp_0.5/withoutTests/cached/artifacts/pull-stream/attempt_1/pending_category/mutant-07128d9/testCase.test.ts

ALLOWED LIBRARIES
You may use:
    1. Any built-in Node.js modules (e.g., fs, path, crypto, etc.).

You may not use any other third-party libraries.

Looking at the mutation, the original code has:
```javascript
else if(end && end !== true) {
  console.warn(doneLackingErr)
  throw end
}
```

The mutated code changes this to:
```javascript
else if(true) {
  console.warn(doneLackingErr)
  throw end
}
```

The key difference: In the original, the `throw end` block only executes when `end` is a truthy error (not `true`). In the mutated version, it always executes when there's no `done` callback - even when `end === true` (normal stream completion).

So the test should:
1. Create a drain without a `done` callback
2. Have the stream end normally (with `true`, not an error)
3. In the original: no throw happens (because `end === true` so the condition is false)
4. In the mutated code: it throws (because `else if(true)` always executes)

```typescript
import drain from "../../../../../../../../../../../subject_repositories/pull-stream/sinks/drain.js";

describe("drain sink without done callback", () => {
  it("should not throw when stream ends normally (end === true) and no done callback is provided", () => {
    // Create a simple source that immediately ends with `true` (normal completion)
    function source(end: any, cb: (end: any, data?: any) => void) {
      cb(true, null);
    }

    // Create drain without a done callback - stream ends normally
    const sink = drain(null);

    // In the original code: end === true, so `else if(end && end !== true)` is false, no throw
    // In the mutated code: `else if(true)` always executes, so it throws `true`
    expect(() => {
      sink(source);
    }).not.toThrow();
  });
});
```
